with cycle as (
  select case when extract(month from current_date) <= 6
              then make_date(extract(year from current_date)::int, 1, 1)
              else make_date(extract(year from current_date)::int, 7, 1) end as start
)
insert into currencies (squadron_id, pilot_id, task, status, cycle_start)
select '00000000-0000-0000-0000-000000000002', v.pilot_id, v.task, v.status, c.start
from cycle c, (values
  ('P101', 'GH', 'done'),
  ('P101', 'IF', 'missing'),
  ('P101', 'NF', 'missing'),
